#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int size = N+1;
        int *cnt = (int*)calloc(size,sizeof(int));
        for(int i=0;i<2*N;i++){
            int x; scanf("%d",&x);
            cnt[x]++;
        }
        int okPrev = 1; // all previous counts >=2
        int answer = 0;
        for(int m=0;m<=N;m++){
            if(cnt[m]==0 && okPrev){ answer=1; break; }
            if(cnt[m]<2) okPrev=0;
        }
        printf(answer?"YES\n":"NO\n");
        free(cnt);
    }
    return 0;
}

